1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	
3	export type Step = { op: string; items?: Item[]; policy?: number; incident?: unknown };
4	
5	export type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: Step[];
8	};
9	
10	export type ScenarioResult = {
11	  results: StepResult[];
12	};
13	
14	const PROCESSING_FEE = 5;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	type StepResult = { premium?: number; payout?: number; remainingCap?: number };
26	
27	const BLOCK_SIZE = 3;
28	const BLOCK_PREMIUM = 60;
29	
30	const CURSE_SURCHARGE_RATE = 0.5;
31	const FIRST_INSURANCE_RATE = 0.1;
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	
35	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
36	
37	const groupKeyFor = (item: Item, index: number): string =>
38	  COMPONENT_TYPES.has(item.type) ? item.type : `item:${index}`;
39	
40	const groupItemsForPricing = (items: Item[]): Item[][] => {
41	  const groups = new Map<string, Item[]>();
42	  items.forEach((item, index) => {
43	    const key = groupKeyFor(item, index);
44	    const group = groups.get(key) ?? [];
45	    group.push(item);
46	    groups.set(key, group);
47	  });
48	  return [...groups.values()];
49	};
50	
51	const premiumForGroup = (group: Item[]): number =>
52	  group.length === BLOCK_SIZE
53	    ? BLOCK_PREMIUM
54	    : group.reduce((total, item) => total + basePremiumFor(item), 0);
55	
56	const totalBasePremiumFor = (items: Item[]): number =>
57	  groupItemsForPricing(items).reduce((total, group) => total + premiumForGroup(group), 0);
58	
59	const curseSurchargeFor = (items: Item[]): number =>
60	  items
61	    .filter((item) => item.cursed)
62	    .reduce((total, item) => total + basePremiumFor(item) * CURSE_SURCHARGE_RATE, 0);
63	
64	const quotePremium = (items: Item[]): number => {
65	  const base = totalBasePremiumFor(items);
66	  const curseSurcharge = curseSurchargeFor(items);
67	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
68	  return Math.ceil(base + curseSurcharge + firstInsuranceSurcharge + PROCESSING_FEE);
69	};
70	
71	const processStep = ({ items = [] }: Step): StepResult => ({ premium: quotePremium(items) });
72	
73	export const runScenario = (scenario: Scenario): ScenarioResult => ({
74	  results: scenario.steps.map(processStep),
75	});
